script.text:

function loadForm(f) {
  setFormDisplay(f);
  f._baseCurrencyValue = f.getItemValue('gt_pb_ky');
  f._foreignCurrencyValue = f.getItemValue('gt_pb_ky_nt');
}
function setFormDisplay (f) {
  setItemDisable(f, 'nguyen_gia_nt, gt_da_pb_nt, gt_cl_nt, nguyen_gia, gt_da_pb, gt_cl', true);
  onChange$EditAllocation(f);
}
function setItemDisable(f, c, v) {
  var a = c.split(',');
  for (var i = 0; i < a.length; i++) {
    var o = f.getItem($func.trim(a[i]));    
    o.disabled = v;
  }
}
function setItemLive(t1, t2, type) {
  if (type) {if (t2.live) {t1.disabled = false; t1.focus();}}
    else {if (t1.live) {t2.disabled = false; t2.focus();}}
}
function onChange$EditAllocation(f, force) {window.setTimeout(String.format('onFocus$EditAllocation(\'{0}\', {1});', f._id, force ? 1 : 0), 2);}
function onFocus$EditAllocation(id, force) {
  var f = $find(id);
  var c = (f.getItemValue('ma_nt') == f._baseCurrency), e = (f.getItemValue('sua_pb') == '0');
  var t1 = f.getItem('ty_gia'), t2 = f.getItem('gt_pb_ky'), t3 = f.getItem('dien_giai');
  if (force) setItemLive(c ? t2 : t1, t3, !e);
  setItemDisable(f, 'gt_pb_ky_nt, ty_gia', c || e);
  setItemDisable(f, 'gt_pb_ky', e);
}
function onChange$FormItem$(o) {
  var f = o.parentForm, name = o.field.Name;
  switch (name) {
    case 'sua_pb':
      onChange$EditAllocation(f, true);
      break;
    case 'ty_gia':
      f.executeExpression(['[gt_pb_ky]:=[gt_pb_ky_nt]*[ty_gia]'], 'gt_pb_ky_nt');
      onchangeBaseCurrencyValue(f);
      break;
    case 'gt_pb_ky_nt':
      f.executeExpression(['[gt_pb_ky]:=[gt_pb_ky_nt]*[ty_gia]']);
      onchangeForeignCurrencyValue(f);
      break;
    case 'gt_pb_ky':
      onchangeBaseCurrencyValue(f);
      break;
    default:
      break;
  }        
}
function onchangeForeignCurrencyValue(f) {
  onchangeItemValue(f, 'nguyen_gia_nt', 'gt_da_pb_nt', 'gt_pb_ky_nt', 'gt_cl_nt', f._foreignCurrencyValue);
  f._foreignCurrencyValue = f.getItemValue('gt_pb_ky_nt');  
  onchangeBaseCurrencyValue(f);
}
function onchangeBaseCurrencyValue(f) {
  onchangeItemValue(f, 'nguyen_gia', 'gt_da_pb', 'gt_pb_ky', 'gt_cl', f._baseCurrencyValue);
  f._baseCurrencyValue = f.getItemValue('gt_pb_ky');
}
function onchangeItemValue(f, c1, c2, c3, c4, v) {
  var n = f.getItemValue(c2), p = f.getItemValue(c3);
  n += (p - v);
  f.setItemValue(c2, n);
  f.setItemValue(c4, f.getItemValue(c1) - n);
}
